  ('social-worker-moex-01111', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於優勢觀點的敘述，下列何者錯誤？', '["透過了解案主的生命經驗與環境脈絡，將焦點轉向可能與希望", "協助服務使用者使用新的語言敘述問題，使其能面對問題的挑戰，讓問題觀點轉為可能觀點", "可以透過詢問個案的例外問題，如「狀況不同會做什麼？」來發掘正向經驗", "強調個人有能力解決自己遭遇的制度與結構上的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
