  ('social-worker-moex-01114', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於結案過程中的工作重點，下列敘述何者錯誤？', '["讓案主覺察是自己的努力才獲得正向改變", "強化案主的正向觀點，以避免未來再次使用社會工作服務", "協助案主檢視處遇所獲，並類化於日常生活中", "鼓勵案主銜接自然網絡中的支持"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01115', 'social-worker', 'social-worker-moex-110-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者進行訪視時需注意的事項，下列敘述何者錯誤？', '["訪視的目的不同，所用的時間與技巧也隨之不同", "要不要事先與案主約定訪視時間，必須經由案主自決", "訪視的服裝可依訪視對象不同而有所調整", "訪視前最好預先查好交通路線"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "d2632f5986ed", "answer_pdf_sha1": "86c7fc48aade", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
